mapper.select:
SELECT commercial_id AS commercialId, biz_name AS bizName, category_large AS categoryLarge, category_medium AS categoryMedium, category_small AS categorySmall, latitude, longitude, address, SQRT( POW((latitude - #{lat}) * 111320, 2) + POW((longitude - #{lng}) * 111320 * COS(RADIANS(#{lat})), 2) ) AS distance FROM commercial_area
category_large = #{category}
HAVING distance <= #{radius} ORDER BY distance ASC, commercial_id ASC
